//go:build linux

package device

import (
	"fmt"

	"github.com/amnezia-vpn/amneziawg-go/tun"
	"golang.org/x/sys/unix"
)

// setTUNPersist toggles the kernel TUNSETPERSIST flag on the TUN device's backing
// file descriptor (Q38/I7). With persistence ON the interface OUTLIVES the fd close
// that Close performs, so the kernel link — and every address, route, and policy
// rule referencing wanbond0 — survives a daemon stop/restart (the D5/I7 production
// failure mode) instead of being reaped when the last fd closes.
//
// It composes with the CreateTUN adoption path: on the next start CreateTUN's
// TUNSETIFF attaches to the still-present persistent device of the same name rather
// than creating a fresh one, so the ifindex is preserved across the restart. Setting
// the flag on an already-persistent adopted device is idempotent (a no-op), so a
// restart-on-failure supervisor loop that repeatedly Up→Close→Up is safe.
//
// It touches ONLY this device's persistence bit and does not disturb the engine, the
// bind, or the amnezia single-engine guard — SIGHUP reload never recreates the TUN,
// so persistence is orthogonal to the reload path.
func setTUNPersist(dev tun.Device, persist bool) error {
	f := dev.File()
	if f == nil {
		return fmt.Errorf("device: TUN has no backing file descriptor for TUNSETPERSIST")
	}
	arg := 0
	if persist {
		arg = 1
	}
	if err := unix.IoctlSetInt(int(f.Fd()), unix.TUNSETPERSIST, arg); err != nil {
		return fmt.Errorf("device: TUNSETPERSIST(%d): %w", arg, err)
	}
	return nil
}

