// It touches ONLY this device's persistence bit and does not disturb the engine, the
// bind, or the amnezia single-engine guard — SIGHUP reload never recreates the TUN,
// so persistence is orthogonal to the reload path.
func setTUNPersist(dev tun.Device, persist bool) error {
	f := dev.File()
	if f == nil {
		return fmt.Errorf("device: TUN has no backing file descriptor for TUNSETPERSIST")
	}
	arg := 0
	if persist {
		arg = 1
	}
	if err := unix.IoctlSetInt(int(f.Fd()), unix.TUNSETPERSIST, arg); err != nil {
		return fmt.Errorf("device: TUNSETPERSIST(%d): %w", arg, err)
	}
	return nil
