//go:build e2e

package e2e

import (
	"os/exec"
	"path/filepath"
	"strconv"
	"strings"
	"syscall"
	"testing"
	"time"
)

// TestTunPersistSurvivesRestart is the T109/I7 acceptance (Q38 code half): with
// tun_persist=true the edge's wanbond0 TUN is set TUNSETPERSIST, so a FULL daemon
// stop/start does NOT drop the interface. The address assigned to wanbond0 (the
// D5/I7 production failure mode: addresses/routes/rules referencing wanbond0 are
// dropped on every restart) survives the stop, and the restarted daemon ADOPTS the
// same persistent device — the ifindex is IDENTICAL across the restart (proving the
// kernel link was reused, not recreated).
//
// D39 / NetworkManager invariant (documented, not asserted here): a persistent
// device still needs the NM unmanaged-devices drop-in on NM hosts. The netns fixture
// runs no NetworkManager, so there is nothing to manage the device; the "does not
// become NM-managed" invariant is a production concern the fixture cannot exercise.
//
// Gated behind the e2e build tag (netns + root); exercised for COMPILATION/vet in CI.
func TestTunPersistSurvivesRestart(t *testing.T) {
	bin := buildWanbond(t)
	top := Setup(t)

	starlink := top.path("starlink")

	edgePriv, edgePub := genKey(t)
	concPriv, concPub := genKey(t)
	psk := randKey(t)

	dir := t.TempDir()
	// Edge opts into persistence: inject the top-level tun_persist key into the
	// shared edge config body (the scalar must precede the first table header, so it
	// goes right after `role`).
	edgeBody := strings.Replace(
		edgeConfigBody(psk, edgePriv, concPub, []pathSpec{starlink}),
		"role = \"edge\"\n", "role = \"edge\"\ntun_persist = true\n", 1)
	edgeCfgPath := writeConfig(t, filepath.Join(dir, "edge.toml"), edgeBody)
	concCfgPath := writeConfig(t, filepath.Join(dir, "conc.toml"),
		concConfigBody(psk, concPriv, edgePub, []pathSpec{starlink}))

	conc := top.startProc(t, "concentrator", "nsenter", "-t", strconv.Itoa(top.pid), "-n", bin, "--config", concCfgPath)
	edge := top.startProc(t, "edge", bin, "--config", edgeCfgPath)

	if !top.waitLink(tunDev, false, 5*time.Second) {
		t.Fatalf("edge %s never appeared\n%s", tunDev, edge.log())
	}
	if !top.waitLink(tunDev, true, 5*time.Second) {
		t.Fatalf("concentrator %s never appeared\n%s", tunDev, conc.log())
	}
	top.run("ip", "addr", "add", edgeInner+"/24", "dev", tunDev)
	top.run("ip", "link", "set", tunDev, "up")
	top.nsenter("ip", "addr", "add", concInner+"/24", "dev", tunDev)
	top.nsenter("ip", "link", "set", tunDev, "up")

	if !top.pingUntil(concInner, 15*time.Second) {
		t.Fatalf("persistent-TUN bond never came up\n--- edge ---\n%s\n--- conc ---\n%s", edge.log(), conc.log())
	}

	idxBefore, ok := linkIndex(t, tunDev)
	if !ok {
		t.Fatalf("%s ifindex not readable before restart", tunDev)
	}

	// --- Full edge daemon STOP: the persistent device must OUTLIVE it. ---
	edge.stop(t)

	if _, ok := linkIndex(t, tunDev); !ok {
		t.Fatalf("%s disappeared after a full daemon stop with tun_persist=true (persistence did not hold)", tunDev)
	}
	if !edgeAddrHas(t, tunDev, edgeInner) {
		t.Fatalf("address %s did not survive the daemon stop on the persistent %s (the D5/I7 failure mode)", edgeInner, tunDev)
	}

	// --- Restart the edge daemon: it must ADOPT the same persistent device. ---
	edge2 := top.startProc(t, "edge-restart", bin, "--config", edgeCfgPath)
	if !top.waitLink(tunDev, false, 5*time.Second) {
		t.Fatalf("edge %s not present after restart\n%s", tunDev, edge2.log())
	}
	idxAfter, ok := linkIndex(t, tunDev)
	if !ok {
		t.Fatalf("%s ifindex not readable after restart", tunDev)
	}
	if idxAfter != idxBefore {
		t.Fatalf("%s ifindex changed across restart: before=%d after=%d — the restarted daemon recreated the device instead of adopting the persistent one", tunDev, idxBefore, idxAfter)
	}
	if !edgeAddrHas(t, tunDev, edgeInner) {
		t.Fatalf("address %s missing after adopting the persistent %s across restart", edgeInner, tunDev)
	}

	// The restarted daemon re-handshakes over the adopted device; connectivity returns
	// WITHOUT re-adding any address/route (they persisted with the link).
	if !top.pingUntil(concInner, 15*time.Second) {
		t.Fatalf("persistent-TUN bond did not recover after edge restart\n--- edge ---\n%s\n--- conc ---\n%s", edge2.log(), conc.log())
	}
	t.Logf("tun_persist: address %s and ifindex %d survived a full edge stop/start; device adopted, bond recovered", edgeInner, idxBefore)
}

// TestTunPersistDefaultTeardown pins the DEFAULT (tun_persist omitted / false): the
// existing teardown semantics are unchanged — wanbond0 DISAPPEARS on a full daemon
// stop, so no persistent link is left behind. This guards against the persistence
// path accidentally becoming the default.
func TestTunPersistDefaultTeardown(t *testing.T) {
	bin := buildWanbond(t)
	top := Setup(t)

	starlink := top.path("starlink")

	edgePriv, edgePub := genKey(t)
	concPriv, concPub := genKey(t)
	psk := randKey(t)

	dir := t.TempDir()
	edgeCfgPath := writeConfig(t, filepath.Join(dir, "edge.toml"),
		edgeConfigBody(psk, edgePriv, concPub, []pathSpec{starlink}))
	concCfgPath := writeConfig(t, filepath.Join(dir, "conc.toml"),
		concConfigBody(psk, concPriv, edgePub, []pathSpec{starlink}))

	conc := top.startProc(t, "concentrator", "nsenter", "-t", strconv.Itoa(top.pid), "-n", bin, "--config", concCfgPath)
	edge := top.startProc(t, "edge", bin, "--config", edgeCfgPath)

	if !top.waitLink(tunDev, false, 5*time.Second) {
		t.Fatalf("edge %s never appeared\n%s", tunDev, edge.log())
	}
	if !top.waitLink(tunDev, true, 5*time.Second) {
		t.Fatalf("concentrator %s never appeared\n%s", tunDev, conc.log())
	}

	edge.stop(t)

	// The non-persistent device must be reaped by the kernel on the last fd close.
	if !waitLinkGone(t, tunDev, 5*time.Second) {
		idx, _ := linkIndex(t, tunDev)
		t.Fatalf("%s (ifindex %d) survived a full daemon stop with tun_persist defaulted false — teardown semantics regressed", tunDev, idx)
	}
	t.Logf("default (tun_persist=false): %s disappeared on daemon stop as before", tunDev)
}

// stop terminates a daemon fully and waits for it to exit (SIGTERM, then SIGKILL
// after a grace period). Unlike the t.Cleanup startProc registers, this is a
// SYNCHRONOUS full stop the test drives mid-body to observe the post-teardown state.
// A second Wait from the cleanup path is harmless (it returns an already-waited
// error the cleanup ignores).
func (p *proc) stop(t *testing.T) {
	t.Helper()
	if p.cmd.Process == nil {
		return
	}
	_ = p.cmd.Process.Signal(syscall.SIGTERM)
	done := make(chan struct{})
	go func() { _ = p.cmd.Wait(); close(done) }()
	select {
	case <-done:
	case <-time.After(3 * time.Second):
		_ = p.cmd.Process.Kill()
		<-done
	}
}

// linkIndex returns the ifindex of dev in the edge (current) network namespace and
// whether it exists. It parses the leading "N:" field of `ip -o link show`.
func linkIndex(t *testing.T, dev string) (int, bool) {
	t.Helper()
	out, err := exec.Command("ip", "-o", "link", "show", dev).CombinedOutput()
	if err != nil {
		return 0, false
	}
	line := strings.TrimSpace(string(out))
	field, _, ok := strings.Cut(line, ":")
	if !ok {
		t.Fatalf("unexpected `ip -o link show %s` output: %q", dev, line)
	}
	idx, perr := strconv.Atoi(strings.TrimSpace(field))
	if perr != nil {
		t.Fatalf("parse ifindex from %q: %v", line, perr)
	}
	return idx, true
}

// edgeAddrHas reports whether addr is currently assigned to dev in the edge netns.
func edgeAddrHas(t *testing.T, dev, addr string) bool {
	t.Helper()
	out, err := exec.Command("ip", "-o", "addr", "show", "dev", dev).CombinedOutput()
	if err != nil {
		return false
	}
	return strings.Contains(string(out), addr+"/")
}

// waitLinkGone polls until dev no longer exists in the edge netns, up to d. The
// kernel reaps a non-persistent tun asynchronously on last fd close, so a short poll
// (not a single check) avoids racing that teardown.
func waitLinkGone(t *testing.T, dev string, d time.Duration) bool {
	t.Helper()
	deadline := time.Now().Add(d)
	for time.Now().Before(deadline) {
		if _, ok := linkIndex(t, dev); !ok {
			return true
		}
		time.Sleep(100 * time.Millisecond)
	}
	return false
}

