// edgeAddrHas reports whether addr is currently assigned to dev in the edge netns.
func edgeAddrHas(t *testing.T, dev, addr string) bool {
	t.Helper()
	out, err := exec.Command("ip", "-o", "addr", "show", "dev", dev).CombinedOutput()
	if err != nil {
		return false
	}
	return strings.Contains(string(out), addr+"/")
}

// waitLinkGone polls until dev no longer exists in the edge netns, up to d. The
// kernel reaps a non-persistent tun asynchronously on last fd close, so a short poll
// (not a single check) avoids racing that teardown.
func waitLinkGone(t *testing.T, dev string, d time.Duration) bool {
	t.Helper()
	deadline := time.Now().Add(d)
	for time.Now().Before(deadline) {
		if _, ok := linkIndex(t, dev); !ok {
			return true
		}
		time.Sleep(100 * time.Millisecond)
	}
	return false
}
